func (k *K8sClient) GetAgentRuntime(namespace, name string) (*unstructured.Unstructured, error) {
	return k.arInformer.GetIndexer().GetByKey(fmt.Sprintf("%s/%s", namespace, name))
}

func (k *K8sClient) GetCodeInterpreter(namespace, name string) (*unstructured.Unstructured, error) {
	return k.ciInformer.GetIndexer().GetByKey(fmt.Sprintf("%s/%s", namespace, name))
}

func (k *K8sClient) resolvePodIP(namespace, sandboxName string) (string, error) {
	k.mu.RLock()
	defer k.mu.RUnlock()

	podName := sandboxName
	obj, exists, err := k.podInformer.GetIndexer().GetByKey(fmt.Sprintf("%s/%s", namespace, podName))
	if err != nil {
		return "", err
	}

	if !exists {
		pods, err := k.podLister.List(labels.SelectorFromSet(labels.Set{
			"runtime.agentcube.io/sandbox-name": sandboxName,
		}))
		if err != nil {
			return "", err
		}
		if len(pods) == 0 {
			return "", fmt.Errorf("no pods found for sandbox %s", sandboxName)
		}
		for _, p := range pods {
			pod := p.(*corev1.Pod)
			if isPodControlledBySandbox(pod, sandboxName) {
				obj = pod
				exists = true
				break
			}
		}
	}

	if !exists {
		return "", fmt.Errorf("pod not found for sandbox %s", sandboxName)
	}

	pod := obj.(*corev1.Pod)
	if pod.Status.Phase != corev1.PodRunning || pod.Status.PodIP == "" {
		return "", fmt.Errorf("pod %s is not running or has no IP", podName)
	}

	return pod.Status.PodIP, nil
}

func isPodControlledBySandbox(pod *corev1.Pod, sandboxName string) bool {
	for _, owner := range pod.OwnerReferences {
		if owner.Kind == "Sandbox" && owner.Name == sandboxName {
			return true
		}
	}
	return false
}

