package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"strings"
	"time"

	"github.com/gin-gonic/gin"
	authenticationv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/klog/v2"

	"github.com/volcano-sh/agentcube/pkg/store"
)

type contextKey string

const (
	contextKeyUserToken          contextKey = "userToken"
	contextKeyServiceAccount     contextKey = "serviceAccount"
	contextKeyServiceAccountName contextKey = "serviceAccountName"
	contextKeyNamespace          contextKey = "namespace"
)

type AuthMiddleware struct {
	clientset kubernetes.Interface
	cache     *TokenCache
}

type TokenCache struct {
	cache map[string]*TokenCacheEntry
	cap   int
	ttl   time.Duration
}

type TokenCacheEntry struct {
	token      string
	username   string
	sa         string
	ns         string
	lastAccess time.Time
}

func NewTokenCache(capacity int, ttl time.Duration) *TokenCache {
	return &TokenCache{
		cache: make(map[string]*TokenCacheEntry),
		cap:   capacity,
		ttl:   ttl,
	}
}

func (tc *TokenCache) Get(key string) (*TokenCacheEntry, bool) {
	entry, ok := tc.cache[key]
	if !ok {
		return nil, false
	}
	if time.Since(entry.lastAccess) > tc.ttl {
		delete(tc.cache, key)
		return nil, false
	}
	entry.lastAccess = time.Now()
	return entry, true
}

func (tc *TokenCache) Set(key string, entry *TokenCacheEntry) {
	if len(tc.cache) >= tc.cap {
		oldest := time.Now()
		var oldestKey string
		for k, v := range tc.cache {
			if v.lastAccess.Before(oldest) {
				oldest = v.lastAccess
				oldestKey = k
			}
		}
		if oldestKey != "" {
			delete(tc.cache, oldestKey)
		}
	}
	tc.cache[key] = entry
}

func newAuthMiddleware() (*AuthMiddleware, error) {
	config, err := getK8sConfig()
	if err != nil {
		return nil, err
	}

	clientset, err := kubernetes.NewForConfig(config)
	if err != nil {
		return nil, err
	}

	return &AuthMiddleware{
		clientset: clientset,
		cache:     NewTokenCache(1000, 5*time.Minute),
	}, nil
}

func authMiddleware(c *gin.Context) {
	authHeader := c.GetHeader("Authorization")
	if authHeader == "" {
		c.JSON(http.StatusUnauthorized, gin.H{"message": "Missing authorization header"})
		c.Abort()
		return
	}

	parts := strings.Split(authHeader, " ")
	if len(parts) != 2 || parts[0] != "Bearer" {
		c.JSON(http.StatusUnauthorized, gin.H{"message": "Invalid authorization header format"})
		c.Abort()
		return
	}

	token := parts[1]
	am, exists := c.Get("authMiddleware")
	if !exists {
		c.JSON(http.StatusInternalServerError, gin.H{"message": "Auth middleware not initialized"})
		c.Abort()
		return
	}

	auth, ok := am.(*AuthMiddleware)
	if !ok {
		c.JSON(http.StatusInternalServerError, gin.H{"message": "Invalid auth middleware type"})
		c.Abort()
		return
	}

	username, saName, namespace, err := auth.validateToken(c.Request.Context(), token)
	if err != nil {
		c.JSON(http.StatusUnauthorized, gin.H{"message": fmt.Sprintf("Token validation failed: %v", err)})
		c.Abort()
		return
	}

	c.Set(string(contextKeyUserToken), token)
	c.Set(string(contextKeyServiceAccount), saName)
	c.Set(string(contextKeyServiceAccountName), saName)
	c.Set(string(contextKeyNamespace), namespace)
	c.Set("username", username)

	c.Next()
}

func (am *AuthMiddleware) validateToken(ctx context.Context, token string) (username, saName, namespace string, err error) {
	if entry, ok := am.cache.Get(token); ok {
		return entry.username, entry.sa, entry.ns, nil
	}

	tr := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := am.clientset.AuthenticationV1().TokenReviews().Create(ctx, tr, metav1.CreateOptions{})
	if err != nil {
		return "", "", "", err
	}

	if !result.Status.Authenticated {
		return "", "", "", fmt.Errorf("token not authenticated")
	}

	username = result.Status.User.Username
	parts := strings.Split(username, ":")
	if len(parts) >= 4 && parts[0] == "system" && parts[1] == "serviceaccount" {
		namespace = parts[2]
		saName = parts[3]
	}

	entry := &TokenCacheEntry{
		token:      token,
		username:   username,
		sa:         saName,
		ns:         namespace,
		lastAccess: time.Now(),
	}
	am.cache.Set(token, entry)

	return username, saName, namespace, nil
}

func loggingMiddleware(c *gin.Context) {
	start := time.Now()
	path := c.Request.URL.Path

	c.Next()

	latency := time.Since(start)
	statusCode := c.Writer.Status()

	klog.Infof("%s %s %d %v", c.Request.Method, path, statusCode, latency)
}

